send(message: JSONRPCMessage): Promise<void> {
  return new Promise((resolve) => {
    const json = serializeMessage(message);
    if (this._stdout.write(json)) {
      resolve();
    } else {
      this._stdout.once("drain", resolve);
    }
  });
}

